#include<bits/stdc++.h>
using namespace std;
struct node
{
    int cnt,id;
    bool operator<(const node&b)const
    {
        if(cnt==b.cnt)
        {
            return id>b.id;
        }
        return cnt>b.cnt;
    }
};
vector<int> mp[200010];
int in[200010];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        memset(in,0,sizeof(in));
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&in[i]);
            for(int j=1;j<=in[i];j++)
            {
                int x;
                scanf("%d",&x);
                mp[x].push_back(i);
            }
        }
        priority_queue<node> q;
        for(int i=1;i<=n;i++)
        {
            if(in[i]==0)
            {
                q.push((node){1,i});
            }
        }
        int ans=0,cnt=0;
        while(!q.empty())
        {
            node t=q.top();
            q.pop();
            cnt++;
            ans=max(ans,t.cnt);
            for(int i:mp[t.id])
            {
                in[i]--;
                if(in[i]==0)
                {
                    if(t.id<i)
                    {
                        q.push((node){t.cnt,i});
                    }
                    else
                    {
                        q.push((node){t.cnt+1,i});
                    }
                }
            }
        }
        if(cnt<n)
        {
            printf("-1\n");
            continue;
        }
        printf("%d\n",ans);
    }
    return 0;
}
